SELECT COUNT(1)
FROM information_schema.TABLES
WHERE TABLE_SCHEMA = #{schema}
  AND TABLE_NAME = #{table}

SELECT COUNT(1)
FROM information_schema.COLUMNS
WHERE TABLE_SCHEMA = #{schema}
  AND TABLE_NAME = #{table}
  AND COLUMN_NAME = #{column}

SELECT COUNT(1)
FROM information_schema.STATISTICS
WHERE TABLE_SCHEMA = #{schema}
  AND TABLE_NAME = #{table}
  AND INDEX_NAME = #{index}
